// ── HOUSE ──────────────────────────────────────────────────────────────
// One button, two boards. Pressing it messages the "garage" board tab —
// switch tabs (or the IDE's board picker) to see the other half.
// Both boards must be connected (each tab keeps its session while parked).
//
// The garage answers with "opened"/"closed"; the RGB LED shows the state.

fn on_start() {
    rgb(0, 0, 25);
    log("press the button to toggle the garage door");
}

fn on_press() {
    send_board("garage", "toggle");   // "*" would broadcast instead
}

fn on_board_msg(from, text) {
    if text == "opened" {
        rgb(0, 60, 0);
        log(`${from}: door is open`);
    } else if text == "closed" {
        rgb(60, 0, 0);
        log(`${from}: door is closed`);
    }
}

// ── GARAGE ─────────────────────────────────────────────────────────────
// The other half of the pair: the house's button drives this servo door,
// and every move is acknowledged back so the house LED stays truthful.

fn on_start() {
    this.open = false;
    door.set_angle(0);
}

fn on_board_msg(from, text) {
    if text != "toggle" { return; }
    this.open = !this.open;
    if this.open {
        door.set_angle(90);
        send_board(from, "opened");
    } else {
        door.set_angle(0);
        send_board(from, "closed");
    }
    log(`door ${if this.open { "opened" } else { "closed" }} (by ${from})`);
}
